import{_ as e,o as r,c as o,ag as a}from"./chunks/framework.BDReElpY.js";const g=JSON.parse('{"title":"Vex Standard Library","description":"","frontmatter":{},"headers":[],"relativePath":"std/index.md","filePath":"std/index.md"}'),d={name:"std/index.md"};function s(n,t,i,c,l,h){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="vex-standard-library" tabindex="-1">Vex Standard Library <a class="header-anchor" href="#vex-standard-library" aria-label="Permalink to &quot;Vex Standard Library&quot;">​</a></h1><p>The Vex Standard Library (<code>std</code>) provides a set of highly optimized, parallelism-first modules to help you build fast, reliable systems. It is written completely in Vex, making use of Vex&#39;s powerful Memory Management (VUMM), Tensor / Vectorization types, and compiler-level built-ins to extract maximum performance from the CPU and GPU.</p><h2 id="core-modules" tabindex="-1">Core Modules <a class="header-anchor" href="#core-modules" aria-label="Permalink to &quot;Core Modules&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>Description</th></tr></thead><tbody><tr><td><strong><a href="./bit"><code>bit</code></a></strong></td><td>Bitwise manipulation, population counts, masking, leading/trailing zero counts mapped directly to hardware vector intrinsics.</td></tr><tr><td><strong><a href="./cli"><code>cli</code></a></strong></td><td>Subcommand, argument, and flag parsing utilities for rapid CLI application development.</td></tr><tr><td><strong><a href="./compress"><code>compress</code></a></strong></td><td>Pure Vex DEFLATE and GZIP compression and decompression paths optimized for the vectorizer.</td></tr><tr><td><strong><a href="./crypto"><code>crypto</code></a></strong></td><td>Core cryptographic algorithms and checksums (e.g. CRC32, AES, MD5) leveraging crypto SIMD instructions (AES-NI) with software fallbacks.</td></tr><tr><td><strong><a href="./db"><code>db</code></a></strong></td><td>Database connections, async pooling, and Native PostgreSQL bindings written purely in Vex without C driver dependencies.</td></tr><tr><td><strong><a href="./fs"><code>fs</code></a></strong></td><td>Buffered asynchronous and synchronous File System operations integrated into the Vex M:N scheduler.</td></tr><tr><td><strong><a href="./hash"><code>hash</code></a></strong></td><td>Extremely fast, non-cryptographic hashing algorithms (FNV-1a, xxHash3, WyHash) optimized for Hash Maps and general probing.</td></tr><tr><td><strong><a href="./http"><code>http</code></a></strong></td><td>Zero-allocation HTTP/1.1 Protocol parsers and baseline Web Server constructs.</td></tr><tr><td><strong><a href="./inference"><code>inference</code></a></strong></td><td>LLM specific primitive abstractions. Holds logic for RoPE, K/V Cache, and Hardware quantizations.</td></tr><tr><td><strong><a href="./io"><code>io</code></a></strong></td><td>Basic cross-platform I/O streams and file descriptors.</td></tr><tr><td><strong><a href="./math"><code>math</code></a></strong></td><td>Math operations ranging from basic arithmetic to advanced trigonometry. Built with GPU <code>graph fn</code> infrastructure for bulk operations.</td></tr><tr><td><strong><a href="./ml"><code>ml</code></a></strong></td><td>High performance Neural Network blocks (RMSNorm, Softmax) executed via Graph blocks.</td></tr><tr><td><strong><a href="./net"><code>net</code></a></strong></td><td>Asynchronous TCP/UDP networking sockets mapped natively to the Vex M:N scheduler loop.</td></tr><tr><td><strong><a href="./regex"><code>regex</code></a></strong></td><td>SIMD-Accelerated zero-copy regex engine compiling to bytecode NFAs.</td></tr><tr><td><strong><a href="./semver"><code>semver</code></a></strong></td><td>Semantic Versioning definitions and query engines.</td></tr><tr><td><strong><a href="./serde"><code>serde</code></a></strong></td><td>A powerful, zero-copy serialization/deserialization framework supporting JSON, TOML, CSV, and MessagePack formats.</td></tr><tr><td><strong><a href="./strings"><code>strings</code></a></strong></td><td>Memory-safe, zero-cost string property lookups (startsWith, endsWith, split).</td></tr><tr><td><strong><a href="./time"><code>time</code></a></strong></td><td>Instant OS monotonic hardware clocks without GC pauses.</td></tr><tr><td><strong><a href="./unicode"><code>unicode</code></a></strong></td><td>Unicode character properties, case folding, and character matching. Powered by binary-searched precompiled tables.</td></tr><tr><td><strong><a href="./url"><code>url</code></a></strong></td><td>Extremely fast, WHATWG-compliant URL parsing and encoding, designed to aggressively reduce small allocations.</td></tr></tbody></table><h2 id="philosophy" tabindex="-1">Philosophy <a class="header-anchor" href="#philosophy" aria-label="Permalink to &quot;Philosophy&quot;">​</a></h2><p>The Vex Standard Library follows a few central design pillars:</p><ol><li><strong>Zero-Copy &amp; Low Allocation</strong>: Functions prefer slices (<code>Span&lt;T&gt;</code>), byte buffers (<code>RawBuf</code>), and minimal heap allocations.</li><li><strong>&quot;Silicon-Ready&quot; Operations</strong>: Wherever there are SIMD instructions or potential for parallelism (hashes, loops, string escapes), the <code>std</code> structures it so <code>vex-compiler</code> can vectorize it directly.</li><li><strong>Extensibility</strong>: Things like <code>Serde</code> are abstracted via <code>contracts</code>, bringing familiar ergonomic usage to a completely custom systems stack.</li></ol>',7)])])}const m=e(d,[["render",s]]);export{g as __pageData,m as default};
